static class DB extends SQLiteOpenHelper{DB(Context c){super(c,"bubyun_driver.db",null,1);}public void onCreate(SQLiteDatabase d){d.execSQL("CREATE TABLE cargo(id TEXT PRIMARY KEY,owner TEXT,phone TEXT,company TEXT,fromc TEXT,toc TEXT,load TEXT,unload TEXT,goods TEXT,weight TEXT,price TEXT,vehicle TEXT,time TEXT,settle TEXT,receiver TEXT,note TEXT,tag TEXT)");d.execSQL("CREATE TABLE bill(no TEXT PRIMARY KEY,cargo_id TEXT,status TEXT,img TEXT)");d.execSQL("CREATE TABLE setting(k TEXT PRIMARY KEY,v TEXT)");}public void onUpgrade(SQLiteDatabase d,int o,int n){d.execSQL("DROP TABLE IF EXISTS cargo");d.execSQL("DROP TABLE IF EXISTS bill");d.execSQL("DROP TABLE IF EXISTS setting");onCreate(d);}}
