int dp(int v){return(int)(v*getResources().getDisplayMetrics().density+0.5f);}String now(String p){return p+new SimpleDateFormat("MMddHHmmss",Locale.CHINA).format(new Date());}TextView tv(String s,int sp,int c,int st){TextView v=new TextView(this);v.setText(s);v.setTextSize(sp);v.setTextColor(c);v.setTypeface(Typeface.DEFAULT,st);v.setPadding(dp(14),dp(6),dp(14),dp(6));return v;}GradientDrawable sh(int c,int r){GradientDrawable g=new GradientDrawable();g.setColor(c);g.setCornerRadius(dp(r));return g;}GradientDrawable st(int c,int r,int sw,int sc){GradientDrawable g=sh(c,r);g.setStroke(dp(sw),sc);return g;}Button btn(String s){Button b=new Button(this);b.setText(s);b.setTextColor(Color.WHITE);b.setTextSize(15);b.setAllCaps(false);b.setBackground(sh(blue,14));return b;}Button lbtn(String s){Button b=new Button(this);b.setText(s);b.setTextColor(blue);b.setTextSize(15);b.setAllCaps(false);b.setBackground(st(Color.WHITE,14,1,Color.rgb(197,215,247)));return b;}
long cnt(String t){Cursor c=db.getReadableDatabase().rawQuery("SELECT COUNT(*) FROM "+t,null);try{return c.moveToFirst()?c.getLong(0):0;}finally{c.close();}}String gc(Cursor c,String n){return c.getString(c.getColumnIndexOrThrow(n));}void set(String k,String v){ContentValues cv=new ContentValues();cv.put("k",k);cv.put("v",v);db.getWritableDatabase().replace("setting",null,cv);}String get(String k,String d){Cursor c=db.getReadableDatabase().query("setting",new String[]{"v"},"k=?",new String[]{k},null,null,null);try{return c.moveToFirst()?c.getString(0):d;}finally{c.close();}}void def(String k,String v){if(get(k,null)==null)set(k,v);}ContentValues cv(Cargo x){ContentValues v=new ContentValues();String[] k={"id","owner","phone","company","fromc","toc","load","unload","goods","weight","price","vehicle","time","settle","receiver","note","tag"};String[] s={x.id,x.owner,x.phone,x.company,x.from,x.to,x.load,x.unload,x.goods,x.weight,x.price,x.vehicle,x.time,x.settle,x.receiver,x.note,x.tag};for(int i=0;i<k.length;i++)v.put(k[i],s[i]);return v;}void save(Cargo x){db.getWritableDatabase().replace("cargo",null,cv(x));}
void save(Waybill w){ContentValues v=new ContentValues();v.put("no",w.no);v.put("cargo_id",w.c.id);v.put("status",w.status);v.put("img",w.img==null?null:w.img.toString());db.getWritableDatabase().replace("bill",null,v);}void del(Waybill w){db.getWritableDatabase().delete("bill","no=?",new String[]{w.no});}
void initData(){if(cnt("cargo")==0){save(new Cargo("HY20260506001","李经理","13800000001","上海云仓供应链","上海","杭州","上海市青浦区华新镇华隆路1688号","杭州市余杭区良渚物流园6号库","电子配件","8 吨","¥2600","9.6 米厢式｜厢内干净｜需尾板","今天 18:00","回单后24小时结算","杭州收货仓","到仓装车，需拍照回传装货单","急装"));save(new Cargo("HY20260506002","王经理","13800000002","深圳鲜达冷链","深圳","广州","深圳市龙岗区平湖冷链园A3仓","广州市白云区江高冷库2号门","生鲜冷链","5 吨","¥1800","冷藏车｜温控2-8℃｜全程记录","今天 21:00","卸货签收后结算","广州白云冷库","整车直达，装卸各1小时","冷链"));save(new Cargo("HY20260506003","陈经理","13800000003","苏州家居集运","苏州","成都","苏州市相城区太平街道金瑞路88号","成都市新都区传化物流基地","家具整车","18 吨","¥8600","13米高栏｜带雨布绑带","明天 08:30","到付50%，回单50%","成都经销仓","轻拿轻放，严禁雨淋","长途"));}if(cnt("bill")==0){ContentValues a=new ContentValues();a.put("no","YD20260506001");a.put("cargo_id","HY20260506002");a.put("status","运输中");db.getWritableDatabase().replace("bill",null,a);ContentValues b=new ContentValues();b.put("no","YD20260506002");b.put("cargo_id","HY20260506003");b.put("status","待装货");db.getWritableDatabase().replace("bill",null,b);}def("driverName",driverName);def("driverPhone",driverPhone);def("plateNo",plateNo);def("driverVehicle",driverVehicle);def("driverCapacity",driverCapacity);def("driverCompany",driverCompany);def("wallet",wallet);def("income",income);}
void load(){cargos.clear();bills.clear();cmap.clear();Cursor c=db.getReadableDatabase().query("cargo",null,null,null,null,null,"rowid DESC");try{while(c.moveToNext()){Cargo x=new Cargo(gc(c,"id"),gc(c,"owner"),gc(c,"phone"),gc(c,"company"),gc(c,"fromc"),gc(c,"toc"),gc(c,"load"),gc(c,"unload"),gc(c,"goods"),gc(c,"weight"),gc(c,"price"),gc(c,"vehicle"),gc(c,"time"),gc(c,"settle"),gc(c,"receiver"),gc(c,"note"),gc(c,"tag"));cargos.add(x);cmap.put(x.id,x);}}finally{c.close();}Cursor w=db.getReadableDatabase().query("bill",null,null,null,null,null,"rowid DESC");try{while(w.moveToNext()){Cargo x=cmap.get(gc(w,"cargo_id"));if(x!=null){Waybill y=new Waybill(gc(w,"no"),x,gc(w,"status"));String im=w.getString(w.getColumnIndexOrThrow("img"));if(im!=null&&im.length()>0)y.img=Uri.parse(im);bills.add(y);}}}finally{w.close();}driverName=get("driverName",driverName);driverPhone=get("driverPhone",driverPhone);plateNo=get("plateNo",plateNo);driverVehicle=get("driverVehicle",driverVehicle);driverCapacity=get("driverCapacity",driverCapacity);driverCompany=get("driverCompany",driverCompany);wallet=get("wallet",wallet);income=get("income",income);}
void build(){root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setBackgroundColor(bg);setContentView(root);content=new LinearLayout(this);content.setOrientation(LinearLayout.VERTICAL);content.setPadding(dp(12),dp(8),dp(12),dp(12));scroll=new ScrollView(this);scroll.addView(content);root.addView(scroll,new LinearLayout.LayoutParams(-1,0,1));nav=new LinearLayout(this);nav.setOrientation(LinearLayout.HORIZONTAL);nav.setPadding(dp(6),dp(4),dp(6),dp(4));nav.setBackgroundColor(Color.WHITE);root.addView(nav,new LinearLayout.LayoutParams(-1,dp(64)));}
void nav(){nav.removeAllViews();tab("首页",v->showHome());tab("发布",v->showPublish());tab("找货",v->showCargo());tab("我的",v->showMe());}void tab(String s,View.OnClickListener l){TextView t=tv((s.equals(active)?"● ":"")+s,15,s.equals(active)?blue:muted,Typeface.BOLD);t.setGravity(Gravity.CENTER);t.setOnClickListener(l);nav.addView(t,new LinearLayout.LayoutParams(0,-1,1));}void clear(String a){active=a;content.removeAllViews();nav();scroll.post(()->scroll.scrollTo(0,0));}void header(String a,String b){content.addView(tv(a,24,deep,Typeface.BOLD));TextView p=tv(b,14,muted,0);p.setPadding(dp(14),0,dp(14),dp(8));content.addView(p);}LinearLayout card(){LinearLayout x=new LinearLayout(this);x.setOrientation(LinearLayout.VERTICAL);x.setPadding(dp(14),dp(12),dp(14),dp(12));x.setBackground(st(Color.WHITE,18,1,Color.rgb(232,237,247)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,-2);lp.setMargins(0,dp(8),0,dp(8));content.addView(x,lp);return x;}void row(LinearLayout b,String k,String v){LinearLayout r=new LinearLayout(this);r.setOrientation(LinearLayout.HORIZONTAL);r.addView(tv(k,14,muted,0),new LinearLayout.LayoutParams(dp(104),-2));r.addView(tv(v,14,deep,Typeface.BOLD),new LinearLayout.LayoutParams(0,-2,1));b.addView(r);}String val(EditText e,String d){String s=e.getText().toString().trim();return s.length()==0?d:s;}int cs(String s){int n=0;for(Waybill w:bills)if(w.status.equals(s))n++;return n;}
TextView money(String txt,int sp,int color,int sty,String key){TextView v=tv(txt,sp,color,sty);v.setOnClickListener(x->{long n=System.currentTimeMillis();if(key.equals("wallet")){if(n-wt<420)editMoney("wallet");wt=n;}else{if(n-it<420)editMoney("income");it=n;}});return v;}void editMoney(String key){EditText e=new EditText(this);e.setSingleLine(true);e.setText(key.equals("wallet")?wallet:income);new AlertDialog.Builder(this).setTitle("编辑金额").setView(e).setPositiveButton("保存",(d,w)->{String v=e.getText().toString().trim();if(v.length()==0)return;if(key.equals("wallet")){wallet=v;set("wallet",v);showMe();}else{income=v;set("income",v);showHome();}}).setNegativeButton("取消",null).show();}
void showHome(){screen="home";load();clear("首页");header("步步云司机","高效接单，安心运输");LinearLayout d=card();d.setBackground(sh(blue,20));d.addView(tv("今日收入",14,Color.rgb(218,232,255),0));d.addView(money(income,30,Color.WHITE,Typeface.BOLD,"income"));d.addView(tv("运输中 "+cs("运输中")+" 单｜待装货 "+cs("待装货")+" 单｜可接货源 "+cargos.size()+" 单",14,Color.WHITE,0));content.addView(tv("推荐货源",18,deep,Typeface.BOLD));for(int i=0;i<Math.min(2,cargos.size());i++)cargoCard(cargos.get(i));}
void showCargo(){screen="cargo";load();clear("找货");header("找货大厅","按路线、车型和装货时间选择货源");for(Cargo x:cargos)cargoCard(x);}void cargoCard(Cargo x){LinearLayout b=card();LinearLayout top=new LinearLayout(this);top.setGravity(Gravity.CENTER_VERTICAL);top.addView(tv(x.from+" → "+x.to,19,deep,Typeface.BOLD),new LinearLayout.LayoutParams(0,-2,1));TextView tag=tv(x.tag,12,blue,Typeface.BOLD);tag.setGravity(Gravity.CENTER);tag.setBackground(st(Color.rgb(236,243,255),12,1,Color.rgb(210,226,255)));top.addView(tag,new LinearLayout.LayoutParams(dp(62),dp(34)));b.addView(top);b.addView(tv(x.company+"｜"+x.owner,14,muted,0));b.addView(tv(x.goods+"｜"+x.weight+"｜"+x.vehicle,15,Color.rgb(65,76,94),0));b.addView(tv("装货时间："+x.time,14,muted,0));b.addView(tv(x.price,22,orange,Typeface.BOLD));Button bt=btn("查看详情 / 立即接单");bt.setOnClickListener(v->cargoDetail(x));b.addView(bt,new LinearLayout.LayoutParams(-1,dp(46)));}
void cargoDetail(Cargo x){screen="cargoDetail";clear("找货");header("货源详情",x.from+" 至 "+x.to);LinearLayout d=card();d.addView(tv(x.goods+"｜"+x.weight,20,deep,Typeface.BOLD));row(d,"货源编号",x.id);row(d,"货主",x.owner+"｜"+x.company);row(d,"装货位置",x.load);row(d,"卸货位置",x.unload);row(d,"车辆要求",x.vehicle);row(d,"装货时间",x.time);row(d,"运费",x.price);row(d,"结算方式",x.settle);row(d,"收货方",x.receiver);row(d,"备注",x.note);Button take=btn("确认接单");take.setOnClickListener(v->{Waybill w=new Waybill(now("YD"),x,"待装货");save(w);load();Toast.makeText(this,"接单成功，已生成运单",Toast.LENGTH_LONG).show();waybillDetail(w);});d.addView(take,new LinearLayout.LayoutParams(-1,dp(48)));}
EditText input(String h){EditText e=new EditText(this);e.setHint(h);e.setTextSize(15);e.setSingleLine(false);e.setMinLines(1);e.setPadding(dp(14),0,dp(14),0);e.setBackground(st(Color.WHITE,14,1,Color.rgb(220,226,237)));LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,dp(52));lp.setMargins(0,dp(6),0,dp(8));content.addView(e,lp);return e;}void sec(String s){content.addView(tv(s,18,deep,Typeface.BOLD));}
void showPublish(){screen="publish";clear("发布");header("发布货源","填写货主与货源信息，发布后可在找货大厅接单");sec("卖家 / 货主信息");EditText owner=input("货主姓名"),phone=input("联系电话"),company=input("公司名称"),receiver=input("收货方");sec("货物与路线");EditText from=input("出发城市"),to=input("目的城市"),load=input("装货位置"),unload=input("卸货位置"),goods=input("货物名称"),weight=input("装货吨数"),time=input("装货时间");sec("运价与要求");EditText price=input("运费"),vehicle=input("车辆要求"),settle=input("结算方式"),note=input("备注");Button b=btn("发布货源");b.setOnClickListener(v->{Cargo c=new Cargo(now("HY"),val(owner,"赵经理"),val(phone,"13800009999"),val(company,"优选货主"),val(from,"上海"),val(to,"杭州"),val(load,"装货仓库"),val(unload,"卸货仓库"),val(goods,"普通货物"),val(weight,"待确认"),val(price,"面议"),val(vehicle,"不限车型"),val(time,"今天"),val(settle,"现付"),val(receiver,"收货方"),val(note,"按约定时间装卸"),"新货源");save(c);load();Toast.makeText(this,"货源已发布",Toast.LENGTH_LONG).show();cargoDetail(c);});content.addView(b,new LinearLayout.LayoutParams(-1,dp(50)));}
void showMe(){screen="me";load();clear("我的");header("我的","司机中心");LinearLayout p=card();LinearLayout top=new LinearLayout(this);top.setGravity(Gravity.CENTER_VERTICAL);top.addView(tv(driverName,22,deep,Typeface.BOLD),new LinearLayout.LayoutParams(0,-2,1));TextView edit=tv("编辑",13,blue,Typeface.BOLD);edit.setGravity(Gravity.CENTER);edit.setBackground(st(Color.rgb(239,246,255),16,1,Color.rgb(197,215,247)));edit.setOnClickListener(v->editDriver());top.addView(edit,new LinearLayout.LayoutParams(dp(64),dp(36)));p.addView(top);p.addView(tv(driverCompany+"｜"+plateNo+"｜"+driverVehicle,15,muted,0));p.addView(tv("手机号："+driverPhone+"｜载重："+driverCapacity,15,muted,0));LinearLayout wa=card();wa.addView(tv("账户余额",14,muted,0));wa.addView(money(wallet,30,orange,Typeface.BOLD,"wallet"));content.addView(tv("我的运单",18,deep,Typeface.BOLD));if(bills.size()==0)content.addView(tv("暂无运单",15,muted,0));for(Waybill w:bills)billCard(w);}
void billCard(Waybill w){LinearLayout b=card();b.addView(tv(w.status+"｜"+w.c.from+" → "+w.c.to,17,blue,Typeface.BOLD));b.addView(tv("运单号："+w.no,13,muted,0));b.addView(tv(w.c.goods+"｜"+w.c.weight+"｜"+w.c.price,15,Color.rgb(65,76,94),0));b.addView(tv("装货："+w.c.time+"｜"+w.c.load,14,muted,0));final float[] sx=new float[1],sy=new float[1];final boolean[] drag=new boolean[1];b.setOnTouchListener((view,e)->{int a=e.getActionMasked();if(a==MotionEvent.ACTION_DOWN){sx[0]=e.getX();sy[0]=e.getY();drag[0]=false;view.animate().cancel();return true;}if(a==MotionEvent.ACTION_MOVE){float dx=e.getX()-sx[0],dy=e.getY()-sy[0];if(Math.abs(dx)>dp(7)&&Math.abs(dx)>Math.abs(dy)){drag[0]=true;view.getParent().requestDisallowInterceptTouchEvent(true);float tx=Math.max(-dp(140),Math.min(0,dx));view.setTranslationX(tx);view.setAlpha(1f-Math.min(.30f,Math.abs(tx)/dp(380)));return true;}return true;}if(a==MotionEvent.ACTION_UP){float dx=e.getX()-sx[0],dy=e.getY()-sy[0];view.getParent().requestDisallowInterceptTouchEvent(false);if(drag[0]&&view.getTranslationX()<-dp(38)){view.animate().translationX(-view.getWidth()).alpha(.15f).setDuration(150).withEndAction(()->{del(w);load();Toast.makeText(this,"运单已删除",Toast.LENGTH_SHORT).show();showMe();}).start();}else{view.animate().translationX(0).alpha(1f).setDuration(120).start();if(!drag[0]&&Math.abs(dx)<dp(12)&&Math.abs(dy)<dp(12))waybillDetail(w);}return true;}if(a==MotionEvent.ACTION_CANCEL){view.getParent().requestDisallowInterceptTouchEvent(false);view.animate().translationX(0).alpha(1f).setDuration(120).start();return true;}return true;});}
void chip(LinearLayout p,Waybill w,String s){Button b=w.status.equals(s)?btn(s):lbtn(s);b.setTextSize(13);b.setOnClickListener(v->{w.status=s;save(w);Toast.makeText(this,"状态已切换为："+s,Toast.LENGTH_SHORT).show();waybillDetail(w);});LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(0,dp(42),1);lp.setMargins(dp(3),0,dp(3),0);p.addView(b,lp);}void waybillDetail(Waybill w){screen="billDetail";clear("我的");TextView back=tv("← 返回我的运单",15,blue,Typeface.BOLD);back.setOnClickListener(v->showMe());content.addView(back);header("运单详情",w.no);LinearLayout sb=card();LinearLayout sr=new LinearLayout(this);sr.setOrientation(LinearLayout.HORIZONTAL);sb.addView(sr);chip(sr,w,"待装货");chip(sr,w,"运输中");chip(sr,w,"已完成");LinearLayout d=card();d.addView(tv(w.status+"｜"+w.c.from+" → "+w.c.to,20,blue,Typeface.BOLD));row(d,"货主",w.c.owner+"｜"+w.c.company);row(d,"联系电话",w.c.phone);row(d,"货物",w.c.goods);row(d,"车辆要求",w.c.vehicle);row(d,"运费",w.c.price);row(d,"结算方式",w.c.settle);row(d,"收货方",w.c.receiver);row(d,"备注",w.c.note);sec("榜单信息");LinearLayout bill=card();row(bill,"装货位置",w.c.load);row(bill,"装货吨数",w.c.weight);row(bill,"装货时间",w.c.time);Button up=lbtn(w.img==null?"上传本地榜单图片":"更换榜单图片");up.setOnClickListener(v->{pending=w;Intent it=new Intent(Intent.ACTION_OPEN_DOCUMENT);it.addCategory(Intent.CATEGORY_OPENABLE);it.setType("image/*");startActivityForResult(it,7);});bill.addView(up,new LinearLayout.LayoutParams(-1,dp(44)));if(w.img!=null){ImageView im=new ImageView(this);im.setImageURI(w.img);im.setScaleType(ImageView.ScaleType.CENTER_CROP);im.setOnClickListener(v->showImage(w.img));bill.addView(im,new LinearLayout.LayoutParams(-1,dp(190)));}sec("运输信息");LinearLayout t=card();row(t,"承运司机",driverName);row(t,"车牌号",plateNo);row(t,"司机电话",driverPhone);row(t,"车辆信息",driverVehicle+"｜"+driverCapacity);}public void onActivityResult(int r,int c,Intent data){super.onActivityResult(r,c,data);if(r==7&&c==RESULT_OK&&data!=null&&pending!=null){Uri u=data.getData();pending.img=u;try{getContentResolver().takePersistableUriPermission(u,Intent.FLAG_GRANT_READ_URI_PERMISSION);}catch(Exception e){}save(pending);Toast.makeText(this,"榜单图片已上传",Toast.LENGTH_SHORT).show();waybillDetail(pending);}}
void showImage(Uri u){Dialog d=new Dialog(this);ImageView im=new ImageView(this);im.setImageURI(u);im.setAdjustViewBounds(true);im.setBackgroundColor(Color.BLACK);im.setOnClickListener(v->d.dismiss());d.setContentView(im);d.show();Window w=d.getWindow();if(w!=null)w.setLayout(-1,-1);}void editDriver(){screen="editDriver";clear("我的");header("修改司机信息","更新承运资料和联系方式");EditText name=input("司机姓名");name.setText(driverName);EditText phone=input("联系电话");phone.setText(driverPhone);EditText plate=input("车牌号");plate.setText(plateNo);EditText vehicle=input("车型车长");vehicle.setText(driverVehicle);EditText cap=input("核载重量");cap.setText(driverCapacity);EditText comp=input("认证/公司信息");comp.setText(driverCompany);Button save=btn("保存信息");save.setOnClickListener(v->{driverName=val(name,driverName);driverPhone=val(phone,driverPhone);plateNo=val(plate,plateNo);driverVehicle=val(vehicle,driverVehicle);driverCapacity=val(cap,driverCapacity);driverCompany=val(comp,driverCompany);set("driverName",driverName);set("driverPhone",driverPhone);set("plateNo",plateNo);set("driverVehicle",driverVehicle);set("driverCapacity",driverCapacity);set("driverCompany",driverCompany);Toast.makeText(this,"司机信息已更新",Toast.LENGTH_LONG).show();showMe();});content.addView(save,new LinearLayout.LayoutParams(-1,dp(50)));}public void onBackPressed(){if("billDetail".equals(screen)||"editDriver".equals(screen)){showMe();return;}if("cargoDetail".equals(screen)){showCargo();return;}super.onBackPressed();}
